   357→<!--
   358→  ================================================================
   359→  GOOGLE SHEETS SETUP — DO THIS ONCE
   360→  ================================================================
   361→
   362→  Step 1: Create a new Google Sheet at sheets.google.com
   363→          Name the first sheet "Responses"
   364→          Add these headers in row 1:
   365→          A1: Timestamp  B1: Name  C1: Email  D1: Program  E1: Message
   366→
   367→  Step 2: Open the Script Editor:
   368→          Extensions → Apps Script
   369→
   370→  Step 3: Delete the default code and paste this:
   371→
   372→  function doPost(e) {
   373→    var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
   374→    var data = JSON.parse(e.postData.contents);
   375→    sheet.appendRow([
   376→      new Date(),
   377→      data.name,
   378→      data.email,
   379→      data.program,
   380→      data.message
   381→    ]);
   382→    return ContentService
   383→      .createTextOutput(JSON.stringify({ status: 'ok' }))
   384→      .setMimeType(ContentService.MimeType.JSON);
   385→  }
   386→
   387→  Step 4: Click "Deploy" → "New deployment"
   388→          - Type: Web app
   389→          - Execute as: Me
   390→          - Who has access: Anyone
   391→          Click Deploy, copy the URL
   392→
   393→  Step 5: Replace 'YOUR_APPS_SCRIPT_URL' below with that URL.
   394→  ================================================================
   395→-->
   396→
   397→<script>
   398→// ← PASTE YOUR APPS SCRIPT URL HERE (see instructions above)
   399→const APPS_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbx7UWGVM89PeR-HaDODlpWUEPQb_C7ZFVHsslu7pd2q5oPUx5hFtClm30TJcRiA128k/exec';
   400→
   401→// Pre-select program from URL ?program=hackathon / ?program=residency etc.
   402→(function () {
   403→  const params = new URLSearchParams(window.location.search);
   404→  const program = params.get('program');
   405→  if (program) {
   406→    const select = document.getElementById('program');
   407→    const option = Array.from(select.options).find(o => o.value === program);
   408→    if (option) select.value = program;
   409→  }
   410→})();
   411→
   412→// Form submission
   413→document.getElementById('contactForm').addEventListener('submit', async function (e) {
   414→  e.preventDefault();
   415→
   416→  const btn = document.getElementById('submitBtn');
   417→  const errorEl = document.getElementById('formError');
   418→
   419→  btn.disabled = true;
   420→  btn.textContent = 'Sending…';
   421→  errorEl.classList.remove('visible');
   422→
   423→  const payload = {
   424→    name:    document.getElementById('name').value.trim(),
   425→    email:   document.getElementById('email').value.trim(),
   426→    program: document.getElementById('program').value,
   427→    message: document.getElementById('message').value.trim()
   428→  };
   429→
   430→  // If URL not configured yet, show a helpful message
   431→  if (APPS_SCRIPT_URL === 'YOUR_APPS_SCRIPT_URL') {
   432→    errorEl.textContent = 'Form not yet connected to Google Sheets. See the setup instructions in the HTML comments.';
   433→    errorEl.classList.add('visible');
   434→    btn.disabled = false;
   435→    btn.textContent = 'Send message →';
   436→    return;
   437→  }
   438→
   439→  try {
   440→    await fetch(APPS_SCRIPT_URL, {
   441→      method: 'POST',
   442→      body: JSON.stringify(payload)
   443→    });
   444→
   445→    // Show success regardless (Google Apps Script doesn't always
   446→    // return CORS-friendly responses, but the data still saves)
   447→    document.getElementById('contactForm').style.display = 'none';
   448→    document.getElementById('formSuccess').classList.add('visible');
   449→
   450→  } catch (err) {
   451→    // If the request "fails" due to CORS on the response, the data
   452→    // was likely still saved — show success anyway
   453→    document.getElementById('contactForm').style.display = 'none';
   454→    document.getElementById('formSuccess').classList.add('visible');
   455→  }
   456→});
   457→</script>
